namespace sv_6668f6ff2b1c4507a28cf22ce9141e4f.Services;

public interface IRecipeService
{
    Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken);
}

namespace sv_6668f6ff2b1c4507a28cf22ce9141e4f.Services;

public sealed class RecipeService : IRecipeService
{
    private static readonly Dictionary<int, List<Recipe>> RecipesByCuisine = new()
    {
        [1] = new List<Recipe>
        {
            new(1, "Margherita Pizza", "Classic pizza with fresh mozzarella, tomatoes, and basil on a thin crust.", 30),
            new(2, "Spaghetti Carbonara", "Creamy pasta with pancetta, egg yolk, and pecorino romano cheese.", 25),
            new(3, "Tiramisu", "Layered dessert with espresso-soaked ladyfingers and mascarpone cream.", 45),
            new(4, "Risotto ai Funghi", "Slow-cooked arborio rice with wild mushrooms and parmesan.", 40),
        },
        [2] = new List<Recipe>
        {
            new(5, "Chicken Tikka Masala", "Grilled chicken in a creamy spiced tomato sauce served with basmati rice.", 50),
            new(6, "Palak Paneer", "Fresh spinach curry with cubes of paneer cheese and aromatic spices.", 35),
            new(7, "Biryani", "Fragrant layered rice dish with marinated meat, saffron, and caramelized onions.", 60),
            new(8, "Samosa", "Crispy pastry filled with spiced potatoes, peas, and cumin.", 45),
        },
        [3] = new List<Recipe>
        {
            new(9, "Tacos al Pastor", "Marinated pork tacos with pineapple, cilantro, and onion on corn tortillas.", 40),
            new(10, "Guacamole", "Fresh avocado dip with lime, cilantro, jalapeño, and tomato.", 10),
            new(11, "Enchiladas Verdes", "Corn tortillas filled with chicken, topped with tangy green salsa and cheese.", 35),
            new(12, "Churros", "Fried dough pastry coated in cinnamon sugar, served with chocolate sauce.", 30),
        },
    };

    public async Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken)
    {
        await Task.Delay(2000, cancellationToken);

        if (RecipesByCuisine.TryGetValue(cuisineId, out var recipes))
        {
            return recipes;
        }

        return new List<Recipe>();
    }
}

@page "/recipes/{CuisineId:int}"
@rendermode InteractiveServer
@implements IDisposable
@using sv_6668f6ff2b1c4507a28cf22ce9141e4f.Services
@inject IRecipeService RecipeService
@inject ILogger<Recipes> Logger
@inject NavigationManager Navigation

<PageTitle>Recipes</PageTitle>

<h1>Recipes</h1>

<nav class="mb-3">
    <a href="/recipes/1" class="btn btn-outline-primary me-1 @(CuisineId == 1 ? "active" : "")">Italian</a>
    <a href="/recipes/2" class="btn btn-outline-primary me-1 @(CuisineId == 2 ? "active" : "")">Indian</a>
    <a href="/recipes/3" class="btn btn-outline-primary me-1 @(CuisineId == 3 ? "active" : "")">Mexican</a>
</nav>

@if (_errorMessage is not null)
{
    <div class="alert alert-danger d-flex align-items-center justify-content-between" role="alert">
        <span>@_errorMessage</span>
        <button class="btn btn-outline-danger btn-sm ms-3" @onclick="RetryAsync">Retry</button>
    </div>
}

@if (_recipes is null && _errorMessage is null)
{
    <div class="d-flex align-items-center gap-2 my-4">
        <div class="spinner-border spinner-border-sm" role="status"></div>
        <span>Loading recipes…</span>
    </div>
}
else if (_recipes is not null)
{
    @if (_isRefreshing)
    {
        <div class="d-flex align-items-center gap-2 mb-3 text-muted">
            <div class="spinner-border spinner-border-sm" role="status"></div>
            <small>Refreshing…</small>
        </div>
    }

    @if (_displayRecipes.Count == 0)
    {
        <p class="text-muted">No recipes found for this cuisine.</p>
    }
    else
    {
        <div class="row row-cols-1 row-cols-md-2 g-3">
            @foreach (var recipe in _displayRecipes)
            {
                <div class="col">
                    <div class="card h-100">
                        <div class="card-body">
                            <h5 class="card-title">@recipe.Title</h5>
                            <p class="card-text">@recipe.Description</p>
                        </div>
                        <div class="card-footer text-muted">
                            <small>Prep time: @recipe.PrepTimeMinutes min</small>
                        </div>
                    </div>
                </div>
            }
        </div>
    }
}

@code {
    private CancellationTokenSource? _loadCts;
    private readonly CancellationTokenSource _disposeCts = new();

    private List<Recipe>? _recipes;
    private bool _isRefreshing;
    private string? _errorMessage;

    private int _loadedCuisineId;

    [Parameter]
    public int CuisineId { get; set; }

    [SupplyParameterFromQuery(Name = "sort")]
    public string? Sort { get; set; }

    private List<Recipe> _displayRecipes =>
        _recipes is null
            ? new List<Recipe>()
            : string.Equals(Sort, "popular", StringComparison.OrdinalIgnoreCase)
                ? _recipes.OrderByDescending(r => r.PrepTimeMinutes).ToList()
                : _recipes.OrderByDescending(r => r.Id).ToList();

    protected override async Task OnParametersSetAsync()
    {
        if (CuisineId == _loadedCuisineId)
        {
            return;
        }

        await LoadRecipesAsync();
    }

    private async Task LoadRecipesAsync()
    {
        // Cancel any in-flight load
        if (_loadCts is not null)
        {
            await _loadCts.CancelAsync();
            _loadCts.Dispose();
        }

        _loadCts = CancellationTokenSource.CreateLinkedTokenSource(_disposeCts.Token);
        var cts = _loadCts;
        var cuisineId = CuisineId;

        _errorMessage = null;
        _isRefreshing = _recipes is not null;

        try
        {
            var result = await RecipeService.GetByCuisineAsync(cuisineId, cts.Token);

            if (cts.Token.IsCancellationRequested)
            {
                return;
            }

            _recipes = result;
            _loadedCuisineId = cuisineId;
        }
        catch (OperationCanceledException) when (_disposeCts.IsCancellationRequested)
        {
            // Component is being disposed — stop silently.
        }
        catch (OperationCanceledException)
        {
            // A newer navigation cancelled this load — stop silently.
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout loading recipes for cuisine {CuisineId}", cuisineId);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error loading recipes for cuisine {CuisineId}", cuisineId);
            _errorMessage = "Something went wrong while loading recipes. Please try again.";
        }
        finally
        {
            _isRefreshing = false;
        }
    }

    private async Task RetryAsync()
    {
        await LoadRecipesAsync();
    }

    public void Dispose()
    {
        _disposeCts.Cancel();
        _disposeCts.Dispose();
        _loadCts?.Dispose();
    }
}

